func (ss *ServiceSentinel) CheckPermission(c *gin.Context, idList iter.Seq[uint64]) bool {
	ss.servicesLock.RLock()
	defer ss.servicesLock.RUnlock()

	for id := range idList {
		if s, ok := ss.services[id]; ok {
			if !s.HasPermission(c) {
				return false
			}
		}
	}
	return true
}

func serviceCanBeReportedByServer(service *model.Service, server *model.Server) bool {
	if service == nil || server == nil {
		return false
	}

	switch service.Cover {
	case model.ServiceCoverAll:
		if service.SkipServers[server.ID] {
			return false
		}
	case model.ServiceCoverIgnoreAll:
		if !service.SkipServers[server.ID] {
			return false
		}
	default:
		return false
	}

	return serviceOwnerCanUseServer(service.UserID, server)
}

func serviceOwnerCanUseServer(ownerID uint64, server *model.Server) bool {
	UserLock.RLock()
	userInfo, ok := UserInfoMap[ownerID]
	UserLock.RUnlock()
	if !ok {
		return ownerID == server.UserID
	}

	return ownerID == server.UserID || userInfo.Role.IsAdmin()
}

